/*
 * Core Dump Demonstration Program
 * Demonstrates OS debugging: core dump generation and configuration
 * 
 * Compile: gcc -g -o core_dump_demo core_dump_demo.c
 * Run: ./core_dump_demo
 * 
 * To generate core dump on crash:
 * ulimit -c unlimited # Set core file size unlimited
 * ./core_dump_demo # Run program to cause segfault
 * gdb ./core_dump_demo core # Analyze the core dump
 */

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <string.h>

/* Global variable to demonstrate stack inspection */
int global_counter = 0;

/* Function to cause segmentation fault */
void cause_segfault() {
 int *null_ptr = NULL;
 printf("About to dereference NULL pointer...\n");
 *null_ptr = 42; /* This will cause SIGSEGV */
}

/* Function to cause division by zero */
void cause_divzero() {
 int x = 10;
 int y = 0;
 printf("About to divide by zero...\n");
 printf("Result: %d\n", x / y); /* This will cause SIGFPE */
}

/* Function demonstrating stack trace */
void level_3() {
 printf(" -> level_3() called\n");
 global_counter = 100;
 /* Uncomment to cause crash: */
 /* cause_segfault(); */
}

void level_2() {
 printf(" -> level_2() called\n");
 level_3();
}

void level_1() {
 printf(" -> level_1() called\n");
 level_2();
}

/* Signal handler to catch signals */
void signal_handler(int signum, siginfo_t *info, void *context) {
 printf("\n=== SIGNAL CAUGHT ===\n");
 printf("Signal number: %d (%s)\n", signum, strsignal(signum));

 if (info != NULL) {
 printf("Fault address: %p\n", info->si_addr);
 printf("Signal code: %d\n", info->si_code);
 }

 printf("\nTo analyze this core dump with gdb:\n");
 printf(" gdb ./core_dump_demo core\n");
 printf(" (gdb) bt # Show backtrace\n");
 printf(" (gdb) info registers # Show register values\n");
 printf(" (gdb) print global_counter # Show variable value\n");

 /* Generate core dump manually */
 abort();
}

void print_core_config_info() {
 printf("\n=== Core Dump Configuration ===\n");
 printf("To configure core dumps, use:\n");
 printf(" ulimit -c unlimited # Bash: unlimited core size\n");
 printf(" sysctl -w kernel.core_pattern=/tmp/core # Set location\n");
 printf("\nCore dump will be saved to:\n");
 printf(" /proc/sys/kernel/core_pattern\n");
 printf("\nCore dump files contain:\n");
 printf(" - Process memory (heap, stack)\n");
 printf(" - Register values\n");
 printf(" - Open file descriptors\n");
 printf(" - Process information\n");
}

void demonstrate_memory_layout() {
 /* Demonstrate different memory segments */
 static int static_var = 10; /* BSS/Data segment */
 int stack_var = 20; /* Stack */
 int *heap_var = malloc(sizeof(int)); /* Heap */
 *heap_var = 30;

 printf("\n=== Memory Layout Demo ===\n");
 printf("Static variable (BSS): %p -> %d\n", (void*)&static_var, static_var);
 printf("Stack variable: %p -> %d\n", (void*)&stack_var, stack_var);
 printf("Heap variable: %p -> %d\n", (void*)heap_var, *heap_var);
 printf("Global variable: %p -> %d\n", (void*)&global_counter, global_counter);

 free(heap_var);
}

void demonstrate_system_info() {
 /* Show /proc/self/status information */
 printf("\n=== Process Info from /proc ===\n");
 FILE *fp = fopen("/proc/self/status", "r");
 if (fp) {
 char line[256];
 printf("Key process metrics:\n");
 while (fgets(line, sizeof(line), fp)) {
 if (strncmp(line, "VmRSS:", 6) == 0 ||
 strncmp(line, "VmSize:", 7) == 0 ||
 strncmp(line, "Pid:", 4) == 0 ||
 strncmp(line, "PPid:", 5) == 0) {
 printf(" %s", line);
 }
 }
 fclose(fp);
 }
}

int main(int argc, char *argv[]) {
 printf("OS Debugging: Core Dump Demo\n");
 printf("================================\n");

 /* Print configuration information */
 print_core_config_info();

 /* Setup signal handlers (for graceful handling) */
 struct sigaction sa;
 memset(&sa, 0, sizeof(sa));
 sa.sa_sigaction = signal_handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = SA_SIGINFO;

 sigaction(SIGSEGV, &sa, NULL); /* Segmentation fault */
 sigaction(SIGFPE, &sa, NULL); /* Floating point exception */

 /* Demonstrate memory layout */
 demonstrate_memory_layout();

 /* Demonstrate /proc filesystem */
 demonstrate_system_info();

 /* Demonstrate function call stack */
 printf("\n=== Function Call Stack Demo ===\n");
 level_1();

 printf("\n=== Available Options ===\n");
 printf("1. Run normally (no crash)\n");
 printf("2. Cause segfault: ./core_dump_demo segfault\n");
 printf("3. Cause divzero: ./core_dump_demo divzero\n");

 /* Check command line argument */
 if (argc > 1) {
 if (strcmp(argv[1], "segfault") == 0) {
 cause_segfault();
 } else if (strcmp(argv[1], "divzero") == 0) {
 cause_divzero();
 }
 }

 printf("\nProgram completed successfully.\n");
 return 0;
}

/*
 * ANALYSIS COMMANDS (after generating core dump):
 * 
 * $ ulimit -c unlimited
 * $ ./core_dump_demo segfault
 * $ gdb ./core_dump_demo core
 * 
 * GDB Commands:
 * bt - Show backtrace (call stack)
 * info frame - Show frame information 
 * print var - Print variable value
 * info registers - Show CPU registers
 * x/100x $sp - Examine 100 words at stack pointer
 * disass - Disassemble current function
 */
